const entrada = $json;
const memoria = $json.memoria || {};

const estado = memoria.estado || null;
const tipo = entrada.tipo_mensaje;
const texto = String(entrada.mensaje_usuario || '').toLowerCase().trim();

const esCancelar = ['cancelar', 'cancela', 'anula', 'salir'].some(x => texto.includes(x));

if (esCancelar) {
  return { ...entrada, accion: 'cancelar' };
}

if (tipo === 'location') {
  if (!estado || estado !== 'visita_abierta') {
    return { ...entrada, accion: 'registrar_entrada' };
  } else {
    return { ...entrada, accion: 'registrar_salida' };
  }
}

if (estado === 'esperando_lead' && tipo === 'text') {
  return { ...entrada, accion: 'procesar_respuesta_lead' };
}

if (estado === 'esperando_crear_oportunidad' && (tipo === 'text' || tipo === 'voice')) {
  return { ...entrada, accion: 'crear_oportunidad' };
}

if (estado === 'esperando_descripcion_visita' && (tipo === 'text' || tipo === 'voice')) {
  return { ...entrada, accion: 'guardar_visita' };
}

return {
  ...entrada,
  accion: 'mensaje_ayuda',
  respuesta_usuario: 'Envíame una ubicación para empezar una visita comercial.'
};

