const memoria = $json.memoria || {};
const pendientes = memoria.datos_pendientes || {};
const opciones = pendientes.oportunidades || [];
const texto = String($json.mensaje_usuario || '').trim().toLowerCase();

if (['cancelar', 'cancela', 'anular'].includes(texto)) {
  return { ...$json, resultado: 'cancelar' };
}

if (texto.includes('crear oportunidad')) {
  return { ...$json, resultado: 'crear_oportunidad' };
}

const n = parseInt(texto, 10);
if (Number.isFinite(n) && n >= 1 && n <= opciones.length) {
  return {
    ...$json,
    resultado: 'lead_elegido',
    lead_id: opciones[n - 1].id,
    lead_name: opciones[n - 1].name
  };
}

const match = opciones.find(o =>
  String(o.name || '').toLowerCase().includes(texto)
);

if (match) {
  return {
    ...$json,
    resultado: 'lead_elegido',
    lead_id: match.id,
    lead_name: match.name
  };
}

return {
  ...$json,
  resultado: 'no_entendido'
};

